mapper.select:
select
id, order_id, order_created_time, wait_pay_time, timeout_canceled_time, user_pay_time, wait_allocation_time,
completed_time, user_canceled_time, wait_refund_time, refund_success_time
from order_status_timeline

    1 = 1 and is_deleted = 0

        and id = #{id}


        and order_id = #{orderId}


        and order_created_time = #{orderCreatedTime}


        and wait_pay_time = #{waitPayTime}


        and timeout_canceled_time = #{timeoutCanceledTime}


        and user_pay_time = #{userPayTime}


        and wait_allocation_time = #{waitAllocationTime}


        and completed_time = #{completedTime}


        and user_canceled_time = #{userCanceledTime}


        and wait_refund_time = #{waitRefundTime}


        and refund_success_time = #{refundSuccessTime}

